import json
import boto3
import functools

SECRET_ARN = "arn:aws:secretsmanager:us-east-1:123456789:secret:prod/agent-XXXXXX"

@functools.lru_cache(maxsize=1)
def _load_bundle() -> dict:
    client = boto3.client("secretsmanager", region_name="us-east-1")
    response = client.get_secret_value(SecretId=SECRET_ARN)
    return json.loads(response["SecretString"])

def get_secret(key: str) -> str:
    bundle = _load_bundle()
    try:
        return bundle[key]
    except KeyError:
        raise KeyError(f"Key '{key}' not found in secret bundle at {SECRET_ARN}")

# Usage — no hardcoded credentials anywhere
llm_key = get_secret("LLM_API_KEY")
db_url   = get_secret("DB_URL")

// npm install @google-cloud/secret-manager
import { SecretManagerServiceClient } from '@google-cloud/secret-manager';

const client = new SecretManagerServiceClient();

// Cache promises to avoid redundant API calls during warm execution
const cache = new Map();

async function getSecret(name) {
  if (cache.has(name)) return cache.get(name);

  const projectId = process.env.GCP_PROJECT_ID;
  const resourceName = `projects/${projectId}/secrets/${name}/versions/latest`;

  const promise = client.accessSecretVersion({ name: resourceName })
    .then(([version]) => version.payload.data.toString('utf8'));

  cache.set(name, promise);
  return promise;
}

// Prefetch all required secrets at startup to fail fast
async function loadSecrets() {
  const [llmKey, oauthSecret, dbUrl] = await Promise.all([
    getSecret('LLM_API_KEY'),
    getSecret('OAUTH_CLIENT_SECRET'),
    getSecret('DB_URL'),
  ]);
  return { llmKey, oauthSecret, dbUrl };
}

const secrets = await loadSecrets();
